package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    @Test
    public void testToString_withValues() {
        String[] values = new String[] { "a", "b", "c" };
        Map<String, Integer> mapping = new HashMap<>();
        CSVRecord record = new CSVRecord(values, mapping, null, 1L);
        String expected = "[a, b, c]";
        assertEquals(expected, record.toString());
    }

    @Test
    public void testToString_withEmptyValues() {
        String[] values = new String[0];
        Map<String, Integer> mapping = Collections.emptyMap();
        CSVRecord record = new CSVRecord(values, mapping, null, 1L);
        String expected = "[]";
        assertEquals(expected, record.toString());
    }

    @Test
    public void testToString_withNullValues() throws Exception {
        // Use reflection to create CSVRecord with null values array
        CSVRecord record = (CSVRecord) java.lang.reflect.Constructor.class
                .getDeclaredConstructor(String[].class, Map.class, String.class, long.class)
                .newInstance(null, null, null, 1L);
        // toString should handle null values gracefully - but since focal method uses Arrays.toString(values),
        // which returns "null" if values is null, expected is "null"
        String expected = "null";
        assertEquals(expected, record.toString());
    }
}
